VALUES
  ('aboriginal-57f41407-moex-00582', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '下列關於普通地上權之敘述，何者正確？', '["地上權設定後，因土地價值之昇降，依原定地租給付顯失公平者，當事人得請求法院增減之", "地上權設定後，地上權人如因不可抗力，妨礙其土地之使用，仍得請求免除或減少租金", "地上權因地上建築物或其他工作物之滅失而消滅", "地上權未定有期限，而有支付地租之約定者，地上權人得支付未到期之三年分地租後，拋棄其權利"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00583', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '關於分管契約於第三人之效力，下列敘述何者錯誤？', '["於共有之不動產，以分管契約經登記者為限，其效力及於應有部分之受讓人", "於區分所有建物，其分管契約之效力及於惡意之應有部分受讓人", "於共有之動產，其分管契約之效力及於惡意之應有部分受讓人", "於已登記之共有不動產，其分管契約非經登記，不得對抗應有部分之受讓人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00584', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '關於合會中，會首之權利及義務，下列敘述何者錯誤？', '["主持標會及通知會員開會", "首期合會金不經投標，由會首取得", "無人出標時，原則上由會首決定何人得標", "代墊會款之義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00585', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '當事人約定，一方委託他方處理事務，他方允為處理之契約，稱為：', '["僱傭契約", "承攬契約", "委任契約", "信託契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00586', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '下列關於民法規定輔助宣告之敘述，何者正確？', '["法院應優先選定受輔助宣告人之配偶擔任輔助人", "受輔助宣告人之財產，由輔助人管理", "輔助開始時，輔助人應於二個月內開具財產清冊，並陳報法院", "輔助人得請求報酬，其數額由法院按其勞力及受監護人之資力酌定之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00587', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '下列何種婚姻關係得撤銷？', '["結婚之證人並未親見親聞雙方當事人有結婚之真意", "婚姻之一方當事人年僅15歲", "四親等旁系血親之表姊與表弟間之婚姻", "有婚姻者，再與第三人結婚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00588', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '甲乙之子女為丙，丁戊之子女為庚。丙庚結婚所生之子女為辛。辛與癸結婚後，辛與丙庚一同出遊遇 難，辛丙庚同時死亡。辛之遺產有新臺幣（下同）1,200萬元，應如何分配該繼承財產？', '["甲繼承100萬元", "丁繼承200萬元", "乙繼承300萬元", "癸繼承400萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00589', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '司法警察在下列情況下詢問犯罪嫌疑人所取得之自白，何者得作為證據？', '["於夜間未經受訊問人同意而詢問", "等候辯護人之時間已超過4小時後，辯護人尚未到場所為之詢問", "將犯罪嫌疑人解送至地方檢察署途中所為之詢問", "犯罪嫌疑人須由通譯傳譯，未等通譯4小時，通譯尚未到場前所為之詢問"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00590', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '甲涉嫌竊盜鄰居乙之財物，為警逮捕到案。下列情形，何者有證據能力？', '["甲不耐疲勞轟炸，乃自白竊盜犯行", "甲已表示選任辯護人之意思，於等候甲選擇並聯繫辯護人之期間，員警仍加以詢問，被告因而自白 竊盜犯行", "甲出於自由意志自白竊盜犯行，且與事實相符", "乙以證人身分於檢察官訊問時作證，卻未具結"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00591', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-55d283b0', 'sub-aboriginal-57f41407-04', NULL, 'single_choice', '刑事訴訟法第293條前段規定，審判非一次期日所能終結者，除有特別情形外，應於次日連續開庭。 此規定係落實下列何種原則？', '["繼續審理原則", "直接審理原則", "公開審理原則", "言詞審理原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
